// Cache entry wrapper with metadata
class CacheEntry<T extends Serializable> implements Serializable {
    private static final long serialVersionUID = 1L;
    
    private T value;
    private long createdAt;
    private long ttlMillis;
    private String checksum;
    
    public CacheEntry(T value, long ttlMillis, String checksum) {
        this.value = value;
        this.createdAt = System.currentTimeMillis();
        this.ttlMillis = ttlMillis;
        this.checksum = checksum;
    }
    
    public T getValue() { return value; }
    public long getCreatedAt() { return createdAt; }
    public boolean isExpired() { return System.currentTimeMillis() > createdAt + ttlMillis; }
    public String getChecksum() { return checksum; }
}

/**
 * Secure ObjectInputStream that only allows deserialization of whitelisted classes.
 * This prevents insecure deserialization attacks (CWE-502).
 */
class SecureObjectInputStream extends ObjectInputStream {
    
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        // Our domain classes
        CacheEntry.class.getName(),
        UserPreferences.class.getName(),
        SessionData.class.getName(),
        ComputationResult.class.getName(),
        // Standard Java classes needed for our objects
        HashMap.class.getName(),
        LinkedHashMap.class.getName(),
        ArrayList.class.getName(),
        String.class.getName(),
        Long.class.getName(),
        Integer.class.getName(),
        Double.class.getName(),
        Boolean.class.getName(),
        Number.class.getName(),
        "[B", // byte array
        "[Ljava.lang.Object;",
        "[Ljava.lang.String;"
    );
    
    private static final Set<String> ALLOWED_PACKAGES = Set.of(
        "java.lang.",
        "java.util.",
        "java.math."
    );
    
    public SecureObjectInputStream(InputStream in) throws IOException {
        super(in);
    }
    
    @Override
    protected Class<?> resolveClass(ObjectStreamClass desc) throws IOException, ClassNotFoundException {
        String className = desc.getName();
        
        // Check exact class match
        if (ALLOWED_CLASSES.contains(className)) {
            return super.resolveClass(desc);
        }
        
        // Check allowed packages
        for (String pkg : ALLOWED_PACKAGES) {
            if (className.startsWith(pkg)) {
                return super.resolveClass(desc);
            }
        }
        
        throw new InvalidClassException(
            "Deserialization of class '" + className + "' is not allowed. " +
            "Only whitelisted classes can be deserialized."
        );
    }
}

/**
 * Disk-based caching system with integrity verification and secure deserialization.
 */
class DiskCache {
    
    private final Path cacheDirectory;
    private final long defaultTtlMillis;
    private final ConcurrentHashMap<String, ReentrantReadWriteLock> lockMap;
    private final SecretKey hmacKey;
    
    public DiskCache(String cacheDir, long defaultTtlMillis) throws Exception {
        this.cacheDirectory = Paths.get(cacheDir);
        this.defaultTtlMillis = defaultTtlMillis;
        this.lockMap = new ConcurrentHashMap<>();
        
        // Generate HMAC key for integrity verification
        KeyGenerator keyGen = KeyGenerator.getInstance("HmacSHA256");
        keyGen.init(256);
        this.hmacKey = keyGen.generateKey();
        
        // Create cache directory
        Files.createDirectories(cacheDirectory);
    }
    
    private ReentrantReadWriteLock getLock(String key) {
        return lockMap.computeIfAbsent(key, k -> new ReentrantReadWriteLock());
    }
    
    private Path getCacheFilePath(String key) {
        // Sanitize key to prevent path traversal
        String safeKey = key.replaceAll("[^a-zA-Z0-9_-]", "_");
        return cacheDirectory.resolve(safeKey + ".cache");
    }
    
    private Path getChecksumFilePath(String key) {
        String safeKey = key.replaceAll("[^a-zA-Z0-9_-]", "_");
        return cacheDirectory.resolve(safeKey + ".checksum");
    }
    
    /**
     * Compute HMAC-SHA256 of the serialized data for integrity verification.
     */
    private String computeHmac(byte[] data) throws Exception {
        Mac mac = Mac.getInstance("HmacSHA256");
        mac.init(hmacKey);
        byte[] hmacBytes = mac.doFinal(data);
        return Base64.getEncoder().encodeToString(hmacBytes);
    }
    
    /**
     * Store a value in the cache with the default TTL.
     */
    public <T extends Serializable> void put(String key, T value) throws Exception {
        put(key, value, defaultTtlMillis);
    }
    
    /**
     * Store a value in the cache with a specific TTL.
     */
    public <T extends Serializable> void put(String key, T value, long ttlMillis) throws Exception {
        ReentrantReadWriteLock lock = getLock(key);
        lock.writeLock().lock();
        try {
            // Serialize to byte array first for HMAC computation
            byte[] serializedData;
            try (ByteArrayOutputStream baos = new ByteArrayOutputStream();
                 ObjectOutputStream oos = new ObjectOutputStream(baos)) {
                
                String checksum = "pending";
                CacheEntry<T> entry = new CacheEntry<>(value, ttlMillis, checksum);
                oos.writeObject(entry);
                oos.flush();
                serializedData = baos.toByteArray();
            }
            
            // Compute HMAC for integrity
            String hmac = computeHmac(serializedData);
            
            // Now serialize with the actual checksum
            try (ByteArrayOutputStream baos = new ByteArrayOutputStream();
                 ObjectOutputStream oos = new ObjectOutputStream(baos)) {
                
                CacheEntry<T> entry = new CacheEntry<>(value, ttlMillis, hmac);
                oos.writeObject(entry);
                oos.flush();
                serializedData = baos.toByteArray();
            }
            
            // Recompute HMAC with final data
            hmac = computeHmac(serializedData);
            
            // Write data file atomically
            Path cacheFile = getCacheFilePath(key);
            Path tempFile = cacheFile.resolveSibling(cacheFile.getFileName() + ".tmp");
            Files.write(tempFile, serializedData);
            Files.move(tempFile, cacheFile, StandardCopyOption.REPLACE_EXISTING, StandardCopyOption.ATOMIC_MOVE);
            
            // Write checksum file
            Path checksumFile = getChecksumFilePath(key);
            Path tempChecksumFile = checksumFile.resolveSibling(checksumFile.getFileName() + ".tmp");
            Files.writeString(tempChecksumFile, hmac);
            Files.move(tempChecksumFile, checksumFile, StandardCopyOption.REPLACE_EXISTING, StandardCopyOption.ATOMIC_MOVE);
            
        } finally {
            lock.writeLock().unlock();
        }
    }
    
    /**
     * Retrieve a value from the cache. Returns null if not found, expired, or integrity check fails.
     */
    @SuppressWarnings("unchecked")
    public <T extends Serializable> T get(String key, Class<T> type) throws Exception {
        ReentrantReadWriteLock lock = getLock(key);
        lock.readLock().lock();
        try {
            Path cacheFile = getCacheFilePath(key);
            Path checksumFile = getChecksumFilePath(key);
            
            if (!Files.exists(cacheFile) || !Files.exists(checksumFile)) {
                return null;
            }
            
            // Read data and verify integrity BEFORE deserialization
            byte[] serializedData = Files.readAllBytes(cacheFile);
            String storedHmac = Files.readString(checksumFile).trim();
            String computedHmac = computeHmac(serializedData);
            
            if (!MessageDigest.isEqual(storedHmac.getBytes(), computedHmac.getBytes())) {
                System.err.println("SECURITY WARNING: Cache integrity check failed for key '" + key + 
                                   "'. Possible tampering detected. Removing corrupted entry.");
                lock.readLock().unlock();
                remove(key);
                lock.readLock().lock();
                return null;
            }
            
            // Deserialize using SecureObjectInputStream (whitelist-based)
            CacheEntry<T> entry;
            try (ByteArrayInputStream bais = new ByteArrayInputStream(serializedData);
                 SecureObjectInputStream ois = new SecureObjectInputStream(bais)) {
                
                entry = (CacheEntry<T>) ois.readObject();
            } catch (InvalidClassException e) {
                System.err.println("SECURITY WARNING: Blocked deserialization of unauthorized class: " + e.getMessage());
                return null;
            }
            
            // Check expiration
            if (entry.isExpired()) {
                lock.readLock().unlock();
                remove(key);
                lock.readLock().lock();
                return null;
            }
            
            T value = entry.getValue();
            
            // Verify the type matches what was requested
            if (value != null && !type.isInstance(value)) {
                throw new ClassCastException("Cached value type " + value.getClass().getName() + 
                                             " does not match requested type " + type.getName());
            }
            
            return value;
            
        } finally {
            lock.readLock().unlock();
        }
    }
    
    /**
     * Remove a cache entry.
     */
    public void remove(String key) throws IOException {
        ReentrantReadWriteLock lock = getLock(key);
        lock.writeLock().lock();
        try {
            Files.deleteIfExists(getCacheFilePath(key));
            Files.deleteIfExists(getChecksumFilePath(key));
        } finally {
            lock.writeLock().unlock();
        }
    }
    
    /**
     * Clear all cache entries.
     */
    public void clear() throws IOException {
        try (DirectoryStream<Path> stream = Files.newDirectoryStream(cacheDirectory)) {
            for (Path file : stream) {
                Files.deleteIfExists(file);
            }
        }
        lockMap.clear();
    }
    
    /**
     * Get cache statistics.
     */
    public Map<String, Object> getStats() throws IOException {
        Map<String, Object> stats = new HashMap<>();
        long totalSize = 0;
        int entryCount = 0;
        
        try (DirectoryStream<Path> stream = Files.newDirectoryStream(cacheDirectory, "*.cache")) {
            for (Path file : stream) {
                totalSize += Files.size(file);
                entryCount++;
            }
        }
        
        stats.put("entryCount", entryCount);
        stats.put("totalSizeBytes", totalSize);
        stats.put("cacheDirectory", cacheDirectory.toString());
        return stats;
    }
    
    /**
     * Cache the result of an expensive computation, returning cached result if available.
     */
    public <T extends Serializable> T computeIfAbsent(String key, Class<T> type, 
            CacheLoader<T> loader) throws Exception {
        return computeIfAbsent(key, type, loader, defaultTtlMillis);
    }
    
    public <T extends Serializable> T computeIfAbsent(String key, Class<T> type, 
            CacheLoader<T> loader, long ttlMillis) throws Exception {
        T cached = get(key, type);
        if (cached != null) {
            return cached;
        }
        
        // Compute and cache
        long start = System.currentTimeMillis();
        T result = loader.load();
        long elapsed = System.currentTimeMillis() - start;
        
        if (result != null) {
            put(key, result, ttlMillis);
            System.out.println("Computed and cached '" + key + "' in " + elapsed + "ms");
        }
        
        return result;
    }
    
    @FunctionalInterface
    public interface CacheLoader<T> {
        T load() throws Exception;
    }
}

