    /**
     * Expensive Fibonacci computation (intentionally slow for demo).
     */
    private static long computeFibonacci(int n) {
        if (n <= 1) return n;
        long a = 0, b = 1;
        for (int i = 2; i <= n; i++) {
            long temp = a + b;
            a = b;
            b = temp;
        }
        // Simulate expensive work
        try { Thread.sleep(500); } catch (InterruptedException ignored) {}
        return b;
    }
